import type { AttachmentOptions, Label, Link, ParameterMode, ParameterOptions, StatusDetails } from "allure-js-commons";
import { Status } from "allure-js-commons";
import { getMessageAndTraceFromError, getStatusFromError, isPromise } from "allure-js-commons/sdk";
import type { SyncTestRuntime, TestRuntime } from "allure-js-commons/sdk/runtime";
import { getGlobalTestRuntime, setGlobalTestRuntime } from "allure-js-commons/sdk/runtime";

import type { AllureCypressTaskArgs, CypressMessage } from "../types.js";
import { enqueueRuntimeMessage, getRuntimeMessages, setRuntimeMessages } from "./state.js";
import { ALLURE_STEP_CMD_SUBJECT, startAllureApiStep, stopCurrentAllureApiStep } from "./steps.js";
import { uint8ArrayToBase64 } from "./utils.js";

const SYNC_STEP_PURE_FUNCTION_ERROR =
  "allure-js-commons/sync step body must be synchronous and must not return a Promise";

export const initTestRuntime = () => setGlobalTestRuntime(new AllureCypressTestRuntime() as TestRuntime);

export const getTestRuntime = () => getGlobalTestRuntime() as AllureCypressTestRuntime;

type SerializedBuffer = {
  type: "Buffer";
  data: number[];
};

class AllureCypressTestRuntime implements TestRuntime {
  constructor() {
    this.#resetMessages();
  }

  get sync(): SyncTestRuntime {
    return this.#createSyncRuntime();
  }

  labels(...labels: Label[]) {
    return this.#enqueueMessageAsync({
      type: "metadata",
      data: {
        labels,
      },
    });
  }

  links(...links: Link[]) {
    return this.#enqueueMessageAsync({
      type: "metadata",
      data: {
        links,
      },
    });
  }

  parameter(name: string, value: string, options?: ParameterOptions) {
    return this.#enqueueMessageAsync({
      type: "metadata",
      data: {
        parameters: [
          {
            name,
            value,
            ...options,
          },
        ],
      },
    });
  }

  description(markdown: string) {
    return this.#enqueueMessageAsync({
      type: "metadata",
      data: {
        description: markdown,
      },
    });
  }

  descriptionHtml(html: string) {
    return this.#enqueueMessageAsync({
      type: "metadata",
      data: {
        descriptionHtml: html,
      },
    });
  }

  displayName(name: string) {
    return this.#enqueueMessageAsync({
      type: "metadata",
      data: {
        displayName: name,
      },
    });
  }

  historyId(value: string) {
    return this.#enqueueMessageAsync({
      type: "metadata",
      data: {
        historyId: value,
      },
    });
  }

  testCaseId(value: string) {
    return this.#enqueueMessageAsync({
      type: "metadata",
      data: {
        testCaseId: value,
      },
    });
  }

  attachment(name: string, content: Uint8Array | Buffer | string, options: AttachmentOptions) {
    const [attachmentContent, actualEncoding] = this.#buildAttachmentContent(
      content as Buffer | string | SerializedBuffer,
    );

    return this.#enqueueMessageAsync({
      type: "attachment_content",
      data: {
        name,
        content: attachmentContent,
        encoding: actualEncoding,
        contentType: options.contentType,
        fileExtension: options.fileExtension,
      },
    });
  }

  attachmentFromPath(name: string, path: string, options: Omit<AttachmentOptions, "encoding">) {
    return this.#enqueueMessageAsync({
      type: "attachment_path",
      data: {
        name,
        path,
        contentType: options.contentType,
        fileExtension: options.fileExtension,
      },
    });
  }

  globalAttachment(name: string, content: Uint8Array | Buffer | string, options: AttachmentOptions) {
    const [attachmentContent, actualEncoding] = this.#buildAttachmentContent(
      content as Buffer | string | SerializedBuffer,
    );

    return this.#enqueueMessageAsync({
      type: "global_attachment_content",
      data: {
        name,
        content: attachmentContent,
        encoding: actualEncoding,
        contentType: options.contentType,
        fileExtension: options.fileExtension,
      },
    });
  }

  globalAttachmentFromPath(name: string, path: string, options: Omit<AttachmentOptions, "encoding">) {
    return this.#enqueueMessageAsync({
      type: "global_attachment_path",
      data: {
        name,
        path,
        contentType: options.contentType,
        fileExtension: options.fileExtension,
      },
    });
  }

  globalError(details: StatusDetails) {
    return this.#enqueueMessageAsync({
      type: "global_error",
      data: details,
    });
  }

  logStep(name: string, status: Status = Status.PASSED, error?: Error): PromiseLike<void> {
    if (this.#isInOriginContext()) {
      startAllureApiStep(name);
      stopCurrentAllureApiStep(status, error ? getMessageAndTraceFromError(error) : undefined);
      return Cypress.Promise.resolve();
    }

    return cy
      .wrap(ALLURE_STEP_CMD_SUBJECT, { log: false })
      .then(() => {
        startAllureApiStep(name);
        return Cypress.Promise.resolve();
      })
      .then(() => {
        stopCurrentAllureApiStep(status, error ? getMessageAndTraceFromError(error) : undefined);
        return Cypress.Promise.resolve();
      });
  }

  step<T = void>(name: string, body: () => T | PromiseLike<T>) {
    return cy
      .wrap(ALLURE_STEP_CMD_SUBJECT, { log: false })
      .then(() => {
        startAllureApiStep(name);
        return Cypress.Promise.resolve(body());
      })
      .then((result) => {
        stopCurrentAllureApiStep();
        return result;
      });
  }

  stepDisplayName(name: string) {
    return this.#enqueueMessageAsync({
      type: "step_metadata",
      data: {
        name,
      },
    });
  }

  stepParameter(name: string, value: string, mode?: ParameterMode) {
    return this.#enqueueMessageAsync({
      type: "step_metadata",
      data: {
        parameters: [{ name, value, mode }],
      },
    });
  }

  flushAllureMessagesToTask(taskName: string) {
    const messages = this.#dequeueAllMessages();
    if (messages.length) {
      cy.task(taskName, { absolutePath: Cypress.spec.absolute, messages }, { log: false });
    }
  }

  flushAllureMessagesToTaskAsync(taskName: string): Cypress.Chainable<unknown> | undefined {
    const messages = this.#dequeueAllMessages();
    if (messages.length) {
      const args: AllureCypressTaskArgs = {
        absolutePath: Cypress.spec.absolute,
        messages,
        isInteractive: Cypress.config("isInteractive"),
      };
      return cy.task(taskName, args, { log: false });
    }
  }

  #resetMessages() {
    setRuntimeMessages([]);
  }

  #enqueueMessageAsync(message: CypressMessage): PromiseLike<void> {
    enqueueRuntimeMessage(message);
    return Cypress.Promise.resolve();
  }

  #dequeueAllMessages() {
    const messages = getRuntimeMessages();
    this.#resetMessages();
    return messages;
  }

  #buildAttachmentContent(content: Uint8Array | Buffer | string | SerializedBuffer): [string, BufferEncoding] {
    const rawContent = this.#normalizeAttachmentContent(content);
    const encoding: BufferEncoding = typeof rawContent === "string" ? "utf8" : "base64";

    return [uint8ArrayToBase64(rawContent), encoding];
  }

  #normalizeAttachmentContent(content: Uint8Array | Buffer | string | SerializedBuffer): string | Uint8Array {
    if (content instanceof Uint8Array || typeof content === "string") {
      return content;
    }

    if (this.#isSerializedBuffer(content)) {
      return new Uint8Array(content.data);
    }

    return content;
  }

  #isSerializedBuffer(content: unknown): content is SerializedBuffer {
    if (!content || typeof content !== "object") {
      return false;
    }

    const candidate = content as Partial<SerializedBuffer>;
    return candidate.type === "Buffer" && Array.isArray(candidate.data);
  }

  #isInOriginContext(): boolean {
    try {
      const hasOriginContext = !!(window as any).cypressOriginContext;
      const hasOriginWindow = !!(window as any).cypressOriginWindow;

      if (hasOriginContext || hasOriginWindow) {
        return true;
      }

      const baseUrl = Cypress.config("baseUrl");
      const currentOrigin = window.location.origin;

      if (baseUrl && currentOrigin !== baseUrl) {
        return true;
      }

      const cypressInstance = (window as any).Cypress;

      if (cypressInstance && cypressInstance.state && cypressInstance.state("origin")) {
        return true;
      }

      try {
        const cyExists = typeof cy !== "undefined";
        const cyTaskExists = typeof cy.task !== "undefined";

        // In cy.origin context, cy.task may not be available or may throw
        if (!cyExists || !cyTaskExists) {
          return true;
        }
      } catch {
        return true;
      }

      return false;
    } catch {
      return true;
    }
  }

  #createSyncRuntime(): SyncTestRuntime {
    return {
      labels: (...labels) =>
        enqueueRuntimeMessage({
          type: "metadata",
          data: {
            labels,
          },
        }),
      links: (...links) =>
        enqueueRuntimeMessage({
          type: "metadata",
          data: {
            links,
          },
        }),
      parameter: (name, value, options) =>
        enqueueRuntimeMessage({
          type: "metadata",
          data: {
            parameters: [
              {
                name,
                value,
                ...options,
              },
            ],
          },
        }),
      description: (markdown) =>
        enqueueRuntimeMessage({
          type: "metadata",
          data: {
            description: markdown,
          },
        }),
      descriptionHtml: (html) =>
        enqueueRuntimeMessage({
          type: "metadata",
          data: {
            descriptionHtml: html,
          },
        }),
      displayName: (name) =>
        enqueueRuntimeMessage({
          type: "metadata",
          data: {
            displayName: name,
          },
        }),
      historyId: (value) =>
        enqueueRuntimeMessage({
          type: "metadata",
          data: {
            historyId: value,
          },
        }),
      testCaseId: (value) =>
        enqueueRuntimeMessage({
          type: "metadata",
          data: {
            testCaseId: value,
          },
        }),
      attachment: (name, content, options) => {
        const [attachmentContent, actualEncoding] = this.#buildAttachmentContent(
          content as Uint8Array | Buffer | string | SerializedBuffer,
        );

        enqueueRuntimeMessage({
          type: "attachment_content",
          data: {
            name,
            content: attachmentContent,
            encoding: actualEncoding,
            contentType: options.contentType,
            fileExtension: options.fileExtension,
          },
        });
      },
      attachmentFromPath: (name, path, options) =>
        enqueueRuntimeMessage({
          type: "attachment_path",
          data: {
            name,
            path,
            contentType: options.contentType,
            fileExtension: options.fileExtension,
          },
        }),
      globalAttachment: (name, content, options) => {
        const [attachmentContent, actualEncoding] = this.#buildAttachmentContent(
          content as Uint8Array | Buffer | string | SerializedBuffer,
        );

        enqueueRuntimeMessage({
          type: "global_attachment_content",
          data: {
            name,
            content: attachmentContent,
            encoding: actualEncoding,
            contentType: options.contentType,
            fileExtension: options.fileExtension,
          },
        });
      },
      globalAttachmentFromPath: (name, path, options) =>
        enqueueRuntimeMessage({
          type: "global_attachment_path",
          data: {
            name,
            path,
            contentType: options.contentType,
            fileExtension: options.fileExtension,
          },
        }),
      globalError: (details) =>
        enqueueRuntimeMessage({
          type: "global_error",
          data: details,
        }),
      logStep: (name, status = Status.PASSED, error) => {
        startAllureApiStep(name);
        stopCurrentAllureApiStep(status, error ? getMessageAndTraceFromError(error) : undefined);
      },
      step: (name, body) => {
        startAllureApiStep(name);

        try {
          const result = body();

          if (isPromise(result)) {
            // eslint-disable-next-line no-console
            console.warn(SYNC_STEP_PURE_FUNCTION_ERROR);
            throw new Error(SYNC_STEP_PURE_FUNCTION_ERROR);
          }

          stopCurrentAllureApiStep();

          return result;
        } catch (err) {
          const error = err as Error;

          stopCurrentAllureApiStep(getStatusFromError(error), getMessageAndTraceFromError(error));
          throw err;
        }
      },
      stepDisplayName: (name) =>
        enqueueRuntimeMessage({
          type: "step_metadata",
          data: {
            name,
          },
        }),
      stepParameter: (name, value, mode) =>
        enqueueRuntimeMessage({
          type: "step_metadata",
          data: {
            parameters: [{ name, value, mode }],
          },
        }),
    };
  }
}
